<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Ubuntu-like Desktop</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    html, body { width: 100%; height: 100%; overflow: hidden; font-family: monospace; }
    #desktop { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background: #1e1e1e; display: flex; flex-direction: column; }
    #taskbar { background: #333; padding: 8px; display: flex; gap: 12px; }
    #open-files, #open-notepad { background: #555; border: none; color: white; padding: 6px 14px; cursor: pointer; border-radius: 3px; }
    #open-files:hover, #open-notepad:hover { background: #777; }
    .window { position: absolute; top: 30%; left: 35%; width: 400px; height: 320px; background: #2d2d2d; border: 1px solid #444; box-shadow: 0 0 15px rgba(0,0,0,0.5); display: none; border-radius: 4px; }
    .title-bar { background: #1a1a1a; padding: 8px; cursor: move; display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid #444; }
    .win-close { background: #c00; color: white; border: none; padding: 4px 8px; cursor: pointer; border-radius: 3px; font-weight: bold; }
    .win-close:hover { background: #a00; }
    #files-path { padding: 8px; color: #aaa; font-size: 14px; }
    #files-up { margin: 8px; padding: 6px 12px; background: #555; color: white; border: none; cursor: pointer; border-radius: 3px; }
    #files-up:hover { background: #777; }
    .listing { padding: 10px; max-height: calc(100% - 60px); overflow-y: auto; }
    .fs-item { padding: 6px 10px; cursor: pointer; border-radius: 3px; }
    .fs-item:hover { background: #444; }
    #notepad-window { width: 450px; height: 400px; top: 25%; left: 30%; }
    #tabs { display: flex; gap: 4px; padding: 8px; background: #1a1a1a; border-bottom: 1px solid #444; }
    .tab { background: #555; padding: 6px 12px; cursor: pointer; border-radius: 3px 3px 0 0; }
    .tab.active { background: #777; }
    #new-tab { background: #555; color: white; border: none; padding: 6px 12px; cursor: pointer; border-radius: 3px 3px 0 0; display: flex; align-items: center; justify-content: center; }
    #new-tab::before { content: '+'; font-size: 18px; }
    #editor { width: 100%; flex: 1; background: #1e1e1e; color: #fff; border: none; padding: 12px; font-family: monospace; font-size: 14px; resize: none; box-sizing: border-box; }
    .scroll-area { flex: 1; overflow-y: auto; }
  </style>
</head>
<body>
  <div id="desktop">
    <div id="taskbar">
      <button id="open-files">Files</button>
      <button id="open-notepad">Notepad</button>
    </div>
    <div id="files-window" class="window">
      <div class="title-bar">Files<span class="win-close">X</span></div>
      <div id="files-path">/</div>
      <button id="files-up">Up</button>
      <div class="scroll-area listing"></div>
    </div>
    <div id="notepad-window" class="window">
      <div class="title-bar">Notepad<span class="win-close">X</span></div>
      <div id="tabs"></div>
      <button id="new-tab"></button>
      <textarea id="editor"></textarea>
    </div>
  </div>

  <script>
    const fileSystem = {
      '/': { type: 'folder', contents: ['bin', 'etc', 'home', 'usr', 'var'] },
      '/bin': { type: 'folder', contents: ['ls', 'cp'] },
      '/etc': { type: 'folder', contents: ['passwd', 'hosts'] },
      '/home': { type: 'folder', contents: ['user'] },
      '/home/user': { type: 'folder', contents: ['Documents', 'Downloads', 'Pictures'] },
      '/home/user/Documents': { type: 'folder', contents: ['report.txt'] },
      '/home/user/Downloads': { type: 'folder', contents: [] },
      '/home/user/Pictures': { type: 'folder', contents: [] },
      '/usr': { type: 'folder', contents: ['bin'] },
      '/var': { type: 'folder', contents: ['log'] }
    };

    function navigateTo(path) {
      const pathEl = document.getElementById('files-path');
      const upBtn = document.getElementById('files-up');
      const listing = document.querySelector('#files-window .listing');

      pathEl.textContent = path;
      upBtn.style.display = path === '/' ? 'none' : 'block';
      listing.innerHTML = '';

      const dir = fileSystem[path];
      if (!dir) return;

      dir.contents.forEach(item => {
        const itemEl = document.createElement('div');
        itemEl.className = 'fs-item';
        itemEl.textContent = item;
        itemEl.addEventListener('dblclick', () => {
          const newPath = path + '/' + item;
          if (fileSystem[newPath]) navigateTo(newPath);
        });
        listing.appendChild(itemEl);
      });
    }

    document.getElementById('open-files').addEventListener('click', () => {
      document.getElementById('files-window').style.display = 'block';
      navigateTo('/');
    });

    document.getElementById('files-up').addEventListener('click', () => {
      const path = document.getElementById('files-path').textContent;
      const parts = path.split('/').filter(p => p);
      if (parts.length > 0) {
        parts.pop();
        navigateTo('/' + parts.join('/'));
      }
    });

    document.querySelectorAll('.win-close').forEach(btn => {
      btn.addEventListener('click', e => {
        e.target.closest('.window').style.display = 'none';
      });
    });

    const notepadKey = 'notepadTabs';

    function loadTabs() {
      const tabs = JSON.parse(localStorage.getItem(notepadKey) || '[]');
      const tabsContainer = document.getElementById('tabs');
      tabsContainer.innerHTML = '';

      tabs.forEach((tab, i) => {
        const tabEl = document.createElement('div');
        tabEl.className = 'tab';
        tabEl.textContent = tab.title || 'Untitled';
        tabEl.addEventListener('click', () => activateTab(i));
        tabsContainer.appendChild(tabEl);
      });

      if (tabs.length === 0) createTab();
      else activateTab(0);
    }

    function createTab() {
      const tabs = JSON.parse(localStorage.getItem(notepadKey) || '[]');
      tabs.push({ title: 'Untitled', content: '' });
      localStorage.setItem(notepadKey, JSON.stringify(tabs));
      loadTabs();
    }

    function activateTab(index) {
      const tabs = JSON.parse(localStorage.getItem(notepadKey) || '[]');
      const editor = document.getElementById('editor');
      const tab = tabs[index];
      editor.value = tab.content;

      document.querySelectorAll('.tab').forEach((t, i) => {
        t.classList.toggle('active', i === index);
      });
    }

    document.getElementById('new-tab').addEventListener('click', createTab);

    document.getElementById('editor').addEventListener('input', () => {
      const tabs = JSON.parse(localStorage.getItem(notepadKey) || '[]');
      const activeIndex = Array.from(document.querySelectorAll('.tab')).findIndex(t => t.classList.contains('active'));
      if (activeIndex !== -1) {
        tabs[activeIndex].content = document.getElementById('editor').value;
        localStorage.setItem(notepadKey, JSON.stringify(tabs));
      }
    });

    document.getElementById('open-notepad').addEventListener('click', () => {
      document.getElementById('notepad-window').style.display = 'block';
      loadTabs();
    });
  </script>
</body>
</html>
